#!/usr/bin/env node
// Reads vendor files from shared/vendor/ and writes shared/vendor.js
// Run this whenever vendor files are updated: node scripts/bundle-vendors.js

const fs = require('fs');
const path = require('path');

const VENDOR_DIR = path.join(__dirname, '..', 'shared', 'vendor');
const OUT_FILE  = path.join(__dirname, '..', 'shared', 'vendor.js');

const entries = [
  { name: 'VENDOR_MERMAID',      file: 'mermaid.min.js' },
  { name: 'VENDOR_REACT',        file: 'react.production.min.js' },
  { name: 'VENDOR_REACT_DOM',    file: 'react-dom.production.min.js' },
  { name: 'VENDOR_BABEL',        file: 'babel.min.js' },
  { name: 'VENDOR_TAILWIND_CSS', file: 'tailwind.min.css' },
  { name: 'VENDOR_RECHARTS',     file: 'Recharts.min.js' },
  { name: 'VENDOR_HLJS',         file: 'highlight.min.js' },
  { name: 'VENDOR_HLJS_CSS',     file: 'highlight-dark.min.css' },
];

const lines = [
  '// shared/vendor.js — AUTO-GENERATED by scripts/bundle-vendors.js — DO NOT EDIT MANUALLY',
  '// Vendor libraries bundled locally to comply with Chrome Web Store MV3 policy.',
  '// To update: replace files in shared/vendor/ and re-run: node scripts/bundle-vendors.js',
  '',
];

for (const { name, file } of entries) {
  const content = fs.readFileSync(path.join(VENDOR_DIR, file), 'utf-8');
  // JSON.stringify produces a valid JS string literal with all special chars escaped
  lines.push(`const ${name} = ${JSON.stringify(content)};`);
  lines.push('');
}

fs.writeFileSync(OUT_FILE, lines.join('\n'), 'utf-8');
console.log(`Written: ${OUT_FILE}`);

const stat = fs.statSync(OUT_FILE);
console.log(`Size: ${(stat.size / 1024 / 1024).toFixed(2)} MB`);
